      src.setData({
        type: 'Feature',
        geometry: { type: 'Point', coordinates: [lon, lat] },
        properties: { bearing: Math.atan2(route[next][0] - route[index][0], route[next][1] - route[index][1]) * 180 / Math.PI }
      });
