      if (idx1 > -1) this._geoJsonLayerIds.splice(idx1, 1);
      var idx2 = this._geoJsonLayerIds.indexOf(polygon._maplibreLineLayerId);
      if (idx2 > -1) this._geoJsonLayerIds.splice(idx2, 1);
