/**
 * BeNomad BeMap JavaScript API - GeoServerInfoResponse
 *
 * Response from `POST service/geoServerInfo/1.0` — the metadata for the
 * geoserver named in the request: the list of services it exposes, the
 * supported travel modes, the per-service resource limits, plus the
 * copyright and supplier-terms strings the customer application is
 * required to display.
 *
 * Wire shape (verified against a live beta response):
 *
 *   {
 *     "availableGeoServerNames": ["osm","addok","here","nominatim"],
 *     "globalCopyright":         "Here Maps 2026.1",
 *     "globalCopyrightUrl":      "https://company.here.com/here/",
 *     "globalSupplierTerms":     "Supplier Terms Applicable to Location Content",
 *     "globalSupplierTermsUrl":  "http://corporate.navteq.com/supplier_terms.html",
 *     "transportTypes":          ["PEDESTRIAN","BICYCLE","MOTORCYCLE","CAR",...],
 *     "truckAttributes":         true,
 *     "servicesInfo":            [{ fieldName, serviceName, title, description }, ...],
 *     "serviceLimits":           [{ serviceName, key, argument, type, value, unit }, ...]
 *   }
 *
 * @since 1.5.0
 * @public
 * @constructor
 */
bemap.GeoServerInfoResponse = function(options) {
    var opts = options || {};
    this.availableGeoServerNames = Array.isArray(opts.availableGeoServerNames) ? opts.availableGeoServerNames.slice() : [];
    this.globalCopyright = opts.globalCopyright || null;
    this.globalCopyrightUrl = opts.globalCopyrightUrl || null;
    this.globalSupplierTerms = opts.globalSupplierTerms || null;
    this.globalSupplierTermsUrl = opts.globalSupplierTermsUrl || null;
    this.transportTypes = Array.isArray(opts.transportTypes) ? opts.transportTypes.slice() : [];
    this.truckAttributes = (opts.truckAttributes === true);
    this.servicesInfo = Array.isArray(opts.servicesInfo) ? opts.servicesInfo : [];
    this.serviceLimits = Array.isArray(opts.serviceLimits) ? opts.serviceLimits : [];
};

bemap.GeoServerInfoResponse.prototype.getAvailableGeoServerNames = function() { return this.availableGeoServerNames; };
bemap.GeoServerInfoResponse.prototype.getGlobalCopyright = function() { return this.globalCopyright; };
bemap.GeoServerInfoResponse.prototype.getGlobalCopyrightUrl = function() { return this.globalCopyrightUrl; };
bemap.GeoServerInfoResponse.prototype.getGlobalSupplierTerms = function() { return this.globalSupplierTerms; };
bemap.GeoServerInfoResponse.prototype.getGlobalSupplierTermsUrl = function() { return this.globalSupplierTermsUrl; };
bemap.GeoServerInfoResponse.prototype.getTransportTypes = function() { return this.transportTypes; };
bemap.GeoServerInfoResponse.prototype.isTruckAttributes = function() { return this.truckAttributes; };
bemap.GeoServerInfoResponse.prototype.getServicesInfo = function() { return this.servicesInfo; };
bemap.GeoServerInfoResponse.prototype.getServiceLimits = function() { return this.serviceLimits; };

/**
 * `true` when the selected geoserver exposes the named service.
 *
 *     info.hasService('Routing')        // true / false
 *     info.hasService('NearPoi')        // true / false
 *
 * @public
 * @param {String} serviceName  As emitted by the server (`'Routing'`, `'Geocoding'`, `'NearPoi'`, ...).
 * @return {Boolean}
 */
bemap.GeoServerInfoResponse.prototype.hasService = function(serviceName) {
    for (var i = 0; i < this.servicesInfo.length; i++) {
        if (this.servicesInfo[i].getServiceName() === serviceName) return true;
    }
    return false;
};

/**
 * `true` when the selected geoserver supports the named travel mode.
 *
 *     info.supportsTransport(bemap.TransportMode.TRUCK)  // true on 'here'
 *
 * @public
 * @param {String} transportType
 * @return {Boolean}
 */
bemap.GeoServerInfoResponse.prototype.supportsTransport = function(transportType) {
    return this.transportTypes.indexOf(transportType) >= 0;
};

/**
 * All limits attached to the named server-side service. Returns `[]` if none.
 *
 *     info.getLimitsForService('BenomadNearPoiService')
 *
 * @public
 * @param {String} serviceName  Server-side bean name (e.g. `'BenomadNearPoiService'`).
 * @return {Array.<bemap.GeoServerServiceLimit>}
 */
bemap.GeoServerInfoResponse.prototype.getLimitsForService = function(serviceName) {
    return this.serviceLimits.filter(function(l) {
        return l.getServiceName() === serviceName;
    });
};

bemap.GeoServerInfoResponse.fromJson = function(json) {
    if (!json) return new bemap.GeoServerInfoResponse();

    var servicesInfo = Array.isArray(json.servicesInfo)
        ? json.servicesInfo.map(function(s) { return bemap.GeoServerServiceInfo.fromJson(s); })
        : [];
    var serviceLimits = Array.isArray(json.serviceLimits)
        ? json.serviceLimits.map(function(l) { return bemap.GeoServerServiceLimit.fromJson(l); })
        : [];

    return new bemap.GeoServerInfoResponse({
        availableGeoServerNames: json.availableGeoServerNames || [],
        globalCopyright: json.globalCopyright,
        globalCopyrightUrl: json.globalCopyrightUrl,
        globalSupplierTerms: json.globalSupplierTerms,
        globalSupplierTermsUrl: json.globalSupplierTermsUrl,
        transportTypes: json.transportTypes || [],
        truckAttributes: json.truckAttributes === true,
        servicesInfo: servicesInfo,
        serviceLimits: serviceLimits
    });
};

/**
 * BeNomad BeMap JavaScript API - GeoServerInfoService (v1.5)
 *
 * Promise-based wrapper around `POST service/geoServerInfo/1.0`. Returns
 * the metadata for a given geoserver: which BeMap services it exposes
 * (Routing, Geocoding, NearPoi, ...), which travel modes it supports,
 * the global copyright + supplier terms strings, and the per-service
 * resource limits (max distance, max via count, max isochrone radius, ...).
 *
 * **Why you want this in a customer app.** Combined with
 * `bemap.AclService.getCurrentUserDetails()` (which tells you _which
 * geoservers_ the user is allowed to use), this service tells you _which
 * services_ each of those geoservers actually exposes — so the UI can
 * disable controls that wouldn't work, surface server-side limits as
 * form hints, and never send a request the server would reject.
 *
 * Typical use:
 *
 *     var info = new bemap.GeoServerInfoService(ctx);
 *     info.getInfo('here').then(function(meta) {
 *         if (!meta.hasService('NearPoi')) hideNearPoiButton();
 *         var maxDist = meta.getLimitsForService('BenomadNearPoiService')
 *             .find(function(l) { return l.getKey() === 'MaxDistance'; });
 *         if (maxDist) updateSliderMax(Number(maxDist.getValue()));
 *     });
 *
 * @since 1.5.0
 * @public
 * @constructor
 * @extends {bemap.ServiceV2}
 * @param {bemap.Context} context BeMap-JS-API Context. Mandatory.
 * @param {Object} [options]
 */
bemap.GeoServerInfoService = function(context, options) {
    bemap.ServiceV2.call(this, context, options);
};
bemap.inherits(bemap.GeoServerInfoService, bemap.ServiceV2);

/**
 * Fetch the metadata for the named geoserver. When `geoserverName` is
 * omitted, the Context's configured geoserver is used.
 *
 * @public
 * @param {String} [geoserverName]
 * @param {Object} [options]
 * @param {String} [options.language]  ISO 639-1 language code for titles / descriptions.
 * @param {Array.<String>} [options.options]  Optional list of `LayersInfoOption` values.
 * @param {AbortSignal} [options.signal]
 * @return {Promise<bemap.GeoServerInfoResponse>}
 */
bemap.GeoServerInfoService.prototype.getInfo = function(geoserverName, options) {
    var opts = options || {};
    var body = {
        geoserver: geoserverName || this.ctx.getGeoserver()
    };
    if (opts.language) body.language = opts.language;
    if (Array.isArray(opts.options) && opts.options.length) body.options = opts.options.slice();

    return this._post('service/geoServerInfo/1.0', body, { signal: opts.signal })
        .then(function(json) {
            return bemap.GeoServerInfoResponse.fromJson(json);
        });
};

/**
 * BeNomad BeMap JavaScript API - GeoServerServiceInfo
 *
 * One entry in `GeoServerInfoResponse.servicesInfo[]`. Describes a single
 * service available for the selected geoserver. Mirrors the server DTO
 * `ServiceInfoFront`:
 *
 *   {
 *     "fieldName":   "routingService",
 *     "serviceName": "Routing",
 *     "title":       "Routing",
 *     "description": "Allow to perform routing computation"
 *   }
 *
 * @since 1.5.0
 * @public
 * @constructor
 */
bemap.GeoServerServiceInfo = function(options) {
    var opts = options || {};
    this.fieldName = opts.fieldName || null;
    this.serviceName = opts.serviceName || null;
    this.title = opts.title || null;
    this.description = opts.description || null;
};

/** Java field name (e.g. `"routingService"`). */
bemap.GeoServerServiceInfo.prototype.getFieldName = function() { return this.fieldName; };
/** Short identifier (e.g. `"Routing"`, `"Geocoding"`, `"NearPoi"`). */
bemap.GeoServerServiceInfo.prototype.getServiceName = function() { return this.serviceName; };
/** Human-readable title. */
bemap.GeoServerServiceInfo.prototype.getTitle = function() { return this.title; };
/** Human-readable description. */
bemap.GeoServerServiceInfo.prototype.getDescription = function() { return this.description; };

bemap.GeoServerServiceInfo.fromJson = function(raw) {
    if (!raw) return new bemap.GeoServerServiceInfo();
    return new bemap.GeoServerServiceInfo({
        fieldName: raw.fieldName,
        serviceName: raw.serviceName,
        title: raw.title,
        description: raw.description
    });
};

/**
 * BeNomad BeMap JavaScript API - GeoServerServiceLimit
 *
 * One entry in `GeoServerInfoResponse.serviceLimits[]`. Describes a single
 * resource-limit applied to a service for the selected geoserver. Mirrors
 * the server DTO `ServiceLmt`:
 *
 *   {
 *     "serviceName": "BenomadNearPoiService",
 *     "key":         "MaxDistance",
 *     "argument":    "MAX",          // "MAX" | "MIN"
 *     "type":        "LONG",         // "INT" | "LONG" | ...
 *     "value":       "1000",         // string (always)
 *     "unit":        "NA"            // "METER" | "SECOND" | "SQUARE_METER" | "NA"
 *   }
 *
 * The `value` field is a String on the wire (the server emits every limit
 * as a string regardless of the underlying type, to preserve precision and
 * avoid Number-precision issues for large longs). `getNumericValue()`
 * returns the parsed Number when `type` is INT or LONG.
 *
 * @since 1.5.0
 * @public
 * @constructor
 */
bemap.GeoServerServiceLimit = function(options) {
    var opts = options || {};
    this.serviceName = opts.serviceName || null;
    this.key = opts.key || null;
    this.argument = opts.argument || null;
    this.type = opts.type || null;
    this.value = (opts.value !== undefined && opts.value !== null) ? String(opts.value) : null;
    this.unit = opts.unit || null;
};

bemap.GeoServerServiceLimit.prototype.getServiceName = function() { return this.serviceName; };
bemap.GeoServerServiceLimit.prototype.getKey = function() { return this.key; };
/** `"MAX"` or `"MIN"`. */
bemap.GeoServerServiceLimit.prototype.getArgument = function() { return this.argument; };
bemap.GeoServerServiceLimit.prototype.getType = function() { return this.type; };
/** Always a String — see class doc. */
bemap.GeoServerServiceLimit.prototype.getValue = function() { return this.value; };
/** `"METER"` / `"SECOND"` / `"SQUARE_METER"` / `"NA"`. */
bemap.GeoServerServiceLimit.prototype.getUnit = function() { return this.unit; };

/**
 * Returns the value as a Number when `type` is INT or LONG, else `NaN`.
 * @return {Number}
 */
bemap.GeoServerServiceLimit.prototype.getNumericValue = function() {
    if (this.value === null) return NaN;
    if (this.type === 'INT' || this.type === 'LONG' || this.type === 'DOUBLE' || this.type === 'FLOAT') {
        return Number(this.value);
    }
    return Number(this.value);
};

bemap.GeoServerServiceLimit.fromJson = function(raw) {
    if (!raw) return new bemap.GeoServerServiceLimit();
    return new bemap.GeoServerServiceLimit({
        serviceName: raw.serviceName,
        key: raw.key,
        argument: raw.argument,
        type: raw.type,
        value: raw.value,
        unit: raw.unit
    });
};

