    this.distance = (typeof opts.distance === 'number') ? opts.distance : 500;
    this.transportType = opts.transportType || bemap.TransportMode.CAR;
    this.orderBy = opts.orderBy || null;
    this.enablePolyline = (typeof opts.enablePolyline === 'boolean') ? opts.enablePolyline : null;
    this.enableEncodedPolyline = (typeof opts.enableEncodedPolyline === 'boolean') ? opts.enableEncodedPolyline : null;
    this.geoserver = opts.geoserver || null;
    this.switchIndex = (typeof opts.switchIndex === 'number') ? opts.switchIndex : null;
