/**
 * BeNomad BeMap JavaScript API - NearPoiResponse
 *
 * Container for the list of `NearPoint` items returned by
 * `bemap.NearPoiSearch.nearPoi()`.
 *
 * Wire shape from the BeMap server — confirmed by a real
 * `POST service/nearpoi/1.0` response on bemap-beta.benomad.com:
 *
 *   {
 *     "pois": [
 *       { coordinate: {lon, lat}, distance, duration, type, name, telephone },
 *       ...
 *     ]
 *   }
 *
 * `fromJson` reads `pois` first, then tolerates a bare root array and the
 * `points` / `items` / `results` wrappers as fallbacks, so consumer code
 * survives if the server tweaks the field name.
 *
 * @since 1.5.0
 * @public
 * @constructor
 * @param {Object} [options]
 * @param {Array.<bemap.NearPoint>} [options.points]
 */
bemap.NearPoiResponse = function(options) {
    var opts = options || {};
    this.points = Array.isArray(opts.points) ? opts.points : [];
};

bemap.NearPoiResponse.prototype.getPoints = function() {
    return this.points;
};

bemap.NearPoiResponse.prototype.size = function() {
    return this.points.length;
};

/**
 * Convenience: return only POIs whose `type` matches one of the values in
 * the supplied list. Pass a single string or an Array of strings.
 *
 * @public
 * @param {String|Array.<String>} typeOrTypes
 * @return {Array.<bemap.NearPoint>}
 */
bemap.NearPoiResponse.prototype.getPointsByType = function(typeOrTypes) {
    var set = Array.isArray(typeOrTypes) ? typeOrTypes : [typeOrTypes];
    return this.points.filter(function(p) {
        return set.indexOf(p.getType()) >= 0;
    });
};

bemap.NearPoiResponse.fromJson = function(json) {
    var resp = new bemap.NearPoiResponse();
    if (!json) return resp;

    // Server-authoritative wrapper is `pois`. The other shapes are
    // tolerance fallbacks for older fixtures and future server tweaks.
    var raw = null;
    if (Array.isArray(json.pois)) raw = json.pois;
    else if (Array.isArray(json)) raw = json;
    else if (Array.isArray(json.points)) raw = json.points;
    else if (Array.isArray(json.items)) raw = json.items;
    else if (Array.isArray(json.results)) raw = json.results;

    if (!raw) return resp;

    for (var i = 0; i < raw.length; i++) {
        resp.points.push(bemap.NearPoint.fromJson(raw[i]));
    }
    return resp;
};

/**
 * BeNomad BeMap JavaScript API - NearPoiSearch (v1.5)
 *
 * Promise-based wrapper around `POST service/nearpoi/1.0`. Returns the POIs
 * reachable from a coordinate within a distance budget.
 *
 * Wire shape mirrors the BeMap server contract (cross-checked against
 * `bemap-flutter-api/lib/service/near_poi/provider/near_poi.dart`).
 *
 * Typical use:
 *
 *   var search = new bemap.NearPoiSearch(ctx);
 *   search.nearPoi(new bemap.NearPoiRequest({
 *       coordinate: new bemap.Coordinate(2.3522, 48.8566),
 *       distance: 800,
 *       transportType: bemap.TransportMode.CAR,
 *       orderBy: bemap.NearPoiOrder.DISTANCE_ASC
 *   })).then(function(response) {
 *       response.getPoints().forEach(function(p) { ... });
 *   });
 *
 * @since 1.5.0
 * @public
 * @constructor
 * @extends {bemap.ServiceV2}
 * @param {bemap.Context} context BeMap-JS-API Context. Mandatory.
 * @param {Object} [options]
 */
bemap.NearPoiSearch = function(context, options) {
    bemap.ServiceV2.call(this, context, options);
};
bemap.inherits(bemap.NearPoiSearch, bemap.ServiceV2);

/**
 * Send a near-POI request.
 *
 * @public
 * @param {bemap.NearPoiRequest|bemap.Coordinate|bemap.CoordinateSat} arg
 *   - A typed `NearPoiRequest` (preferred).
 *   - Or a bare coordinate; in that case the second argument carries
 *     `{ distance, transportType, orderBy, enablePolyline, enableEncodedPolyline }`.
 * @param {Object} [filters] Filter shorthand when the first arg is a bare coordinate.
 * @param {Object} [options]
 * @param {String} [options.geoserver]
 * @param {AbortSignal} [options.signal]
 * @return {Promise<bemap.NearPoiResponse>}
 */
bemap.NearPoiSearch.prototype.nearPoi = function(arg, filters, options) {
    var request;
    var opts;
    if (arg instanceof bemap.NearPoiRequest) {
        request = arg;
        opts = filters || {};
    } else if (arg instanceof bemap.Coordinate || arg instanceof bemap.CoordinateSat
            || (arg && typeof arg.lon === 'number' && typeof arg.lat === 'number')) {
        var merged = { coordinate: arg };
        if (filters) {
            for (var k in filters) {
                if (Object.prototype.hasOwnProperty.call(filters, k)) merged[k] = filters[k];
            }
        }
        request = new bemap.NearPoiRequest(merged);
        opts = options || {};
    } else {
        return Promise.reject(new bemap.Error({
            code: bemap.Error.NETWORK,
            message: 'NearPoiSearch.nearPoi requires a NearPoiRequest or a Coordinate'
        }));
    }

    var body = request.toJson();
    if (!body.geoserver) body.geoserver = opts.geoserver || this.ctx.getGeoserver();

    return this._post('service/nearpoi/1.0', body, opts)
        .then(function(json) {
            return bemap.NearPoiResponse.fromJson(json);
        });
};

/**
 * BeNomad BeMap JavaScript API - NearPoint
 *
 * One POI in the array returned by `bemap.NearPoiSearch.nearPoi()`.
 *
 * Wire shape from the BeMap server (cross-checked against a real
 * `POST service/nearpoi/1.0` response):
 *
 *   {
 *     coordinate: { lon, lat },   // POI location
 *     distance:   long,           // straight-line distance from the search centre, in metres
 *     duration:   long,           // estimated travel duration for the active transport mode, in seconds
 *     type:       string,         // POI category code, e.g. "RESTAURANT" / "HOTEL_MOTEL" / "RENT_A_CAR" / "PHARMACY" / ...
 *     name:       string,         // POI display name (may be empty for unnamed POIs like parking areas)
 *     telephone:  string          // POI phone number when known (may be empty)
 *   }
 *
 * @since 1.5.0
 * @public
 * @constructor
 * @param {Object} [options]
 * @param {bemap.Coordinate} [options.coordinate]
 * @param {Number} [options.distance]    Metres.
 * @param {Number} [options.duration]    Seconds.
 * @param {String} [options.type]        Server category code.
 * @param {String} [options.name]
 * @param {String} [options.telephone]
 * @param {String} [options.id]          Convenience; not emitted by the server.
 * @param {bemap.PostalAddress} [options.postalAddress] Reserved for future server fields.
 * @param {Object} [options.extra]
 */
bemap.NearPoint = function(options) {
    var opts = options || {};
    this.coordinate = opts.coordinate || null;
    this.distance = (typeof opts.distance === 'number') ? opts.distance : null;
    this.duration = (typeof opts.duration === 'number') ? opts.duration : null;
    this.type = opts.type || null;
    // name / telephone use a type-check rather than `||` so the server's
    // empty-string values (parking areas, partial records) survive.
    this.name = (typeof opts.name === 'string') ? opts.name : null;
    this.telephone = (typeof opts.telephone === 'string') ? opts.telephone : null;
    this.id = opts.id || null;
    this.postalAddress = opts.postalAddress || null;
    this.extra = opts.extra || null;
};

bemap.NearPoint.prototype.getCoordinate = function() { return this.coordinate; };
/** @public — metres. */
bemap.NearPoint.prototype.getDistance = function() { return this.distance; };
/** @public — seconds for the active transport mode. */
bemap.NearPoint.prototype.getDuration = function() { return this.duration; };
/** @public — server category code, e.g. "RESTAURANT", "HOTEL_MOTEL". */
bemap.NearPoint.prototype.getType = function() { return this.type; };
bemap.NearPoint.prototype.getName = function() { return this.name; };
bemap.NearPoint.prototype.getTelephone = function() { return this.telephone; };
bemap.NearPoint.prototype.getId = function() { return this.id; };
bemap.NearPoint.prototype.getPostalAddress = function() { return this.postalAddress; };
bemap.NearPoint.prototype.getExtra = function() { return this.extra; };

/* Compatibility aliases — earlier drafts used `category` / `poiClass`. */
bemap.NearPoint.prototype.getCategory = function() { return this.type; };
bemap.NearPoint.prototype.getPoiClass = function() { return this.type; };

bemap.NearPoint.fromJson = function(raw) {
    if (!raw) return new bemap.NearPoint();

    var coord = null;
    if (raw.coordinate) {
        var lon = (raw.coordinate.lon !== undefined)
            ? raw.coordinate.lon
            : (raw.coordinate.longitude !== undefined) ? raw.coordinate.longitude : null;
        var lat = (raw.coordinate.lat !== undefined)
            ? raw.coordinate.lat
            : (raw.coordinate.latitude !== undefined) ? raw.coordinate.latitude : null;
        if (lon !== null && lat !== null) coord = new bemap.Coordinate(lon, lat);
    }

    var postal = null;
    if (raw.postalAddress) {
        postal = new bemap.PostalAddress({
            countryCode: raw.postalAddress.countryCode,
            country: raw.postalAddress.country,
            state: raw.postalAddress.state,
            county: raw.postalAddress.county,
            city: raw.postalAddress.city,
            district: raw.postalAddress.district,
            postalCode: raw.postalAddress.postalCode,
            street: raw.postalAddress.street,
            streetNumber: raw.postalAddress.streetNumber
        });
    }

    return new bemap.NearPoint({
        coordinate: coord,
        distance: (typeof raw.distance === 'number') ? raw.distance : null,
        duration: (typeof raw.duration === 'number') ? raw.duration : null,
        type: raw.type || raw.poiClass || raw['class'] || raw.category || null,
        name: (typeof raw.name === 'string') ? raw.name : null,
        telephone: (typeof raw.telephone === 'string') ? raw.telephone : null,
        id: raw.id || null,
        postalAddress: postal,
        extra: raw.extra || null
    });
};

